tspan = [0 90]; % Simulate over 60 minutes
EDA = load("EDA_preprocessed\S4M1EDA.mat");  % EDA
EDA = EDA.S4M1EDA;
figure %[output:021e377d]
plot(EDA) %[output:021e377d]
EDA = EDA.*10^-6;
EDA = EDA' %[output:333e6308]

HR = load("Data\M1\HeartRate\S4HR.csv");% HR
figure %[output:44739aa7]
plot(HR) %[output:44739aa7]
ylim([50 200]) %[output:44739aa7]
fs_EDA = 4;
fs_HR = 1;
t_EDA = ((0:length(EDA)-1) / fs_EDA);
t_HR = ((0:length(HR)-1) / fs_HR);


%%

%% Interpolating data
C0 = 0;  % Initial cognitive load
EDA = @(t) interp1(t_EDA, EDA, t, 'linear') %[output:48be23bf]
HR = @(t) interp1(t_HR, HR, t, 'linear');
%%

t_start = max(min(t_EDA), min(t_HR));
t_end = min(max(t_EDA), max(t_HR));

  % Adjust 0.1 as needed for resolution
alpha = 1.2;
beta = 0.8;
gamma = 0.5;

dCdt = @(t, C) alpha * EDA(t) + beta * HR(t) - gamma * C;
C0 = 0;

[t_sol, C_sol] = ode45(dCdt, [t_start, t_end], C0);
%%

figure; %[output:4487876f]
plot(t_sol, C_sol, 'LineWidth', 2); %[output:4487876f]
xlabel('Time (seconds)'); %[output:4487876f]
ylabel('Cognitive Load'); %[output:4487876f]
title('Cognitive Load Over Time'); %[output:4487876f]
grid on; %[output:4487876f]

CL_range = max(C_sol) - min(C_sol) %[output:1812bea4]



